def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    if len(prs.slides) < 3:
        return "Modified presentation does not have 3 slides.", 0.0

    slide = prs.slides[2]  # Slide 3

    # Collect all text from shapes
    texts = []
    for shape in slide.shapes:
        if hasattr(shape, 'text') and shape.text:
            text = shape.text.strip().lower()
            if text:
                texts.append(text)

    # Check for required flowchart components (exact, case-insensitive match of full shape text)
    required_terms = ["left hand side", "right hand side", "balance"]
    texts_set = set(texts)  # exact matches (already lowercased & stripped)
    found_terms = []
    for required_term in required_terms:
        for text in texts_set:
            if required_term in text:
                found_terms.append(required_term)
                break

    missing_terms = [term for term in required_terms if term not in found_terms]

    total = len(required_terms)
    found_count = len(found_terms)

    # Partial credit: proportion of required terms present
    score = found_count / total

    if found_count == total:
        return (
            f"Flowchart contains all required components (exact matches): {', '.join(found_terms)}",
            1.0,
        )
    elif found_count == 0:
        return (
            "Flowchart is missing all required components: "
            + ", ".join(required_terms),
            0.0,
        )
    else:
        return (
            "Flowchart partially complete. Found: "
            + (", ".join(found_terms) if found_terms else "<none>")
            + "; Missing: "
            + ", ".join(missing_terms)
            + f" (score {score:.2f})",
            score,
        )

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE, MSO_AUTO_SHAPE_TYPE

    prs = Presentation(modified_ppt_path)

    if len(prs.slides) < 3:
        return "Modified presentation does not have 3 slides.", 0.0

    slide = prs.slides[2]  # Slide 3

    # Count specific appropriate shapes for flowchart
    rounded_rectangles = 0  # Rounded rectangles (preferred for flowchart steps)
    other_step_shapes = 0   # Other valid step shapes (rectangles, etc.)
    arrow_connectors = 0    # Line connectors/arrows

    for shape in slide.shapes:
        if shape.is_placeholder:
            continue

        if shape.shape_type == MSO_SHAPE_TYPE.AUTO_SHAPE:
            # Check if it's specifically a rounded rectangle (best for flowcharts)
            if hasattr(shape, 'auto_shape_type') and shape.auto_shape_type == MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE:
                rounded_rectangles += 1
            # Or other valid flowchart step shapes
            elif hasattr(shape, 'auto_shape_type') and shape.auto_shape_type in [
                MSO_AUTO_SHAPE_TYPE.RECTANGLE, 
                MSO_AUTO_SHAPE_TYPE.FLOWCHART_PROCESS,
                MSO_AUTO_SHAPE_TYPE.FLOWCHART_DECISION,
                MSO_AUTO_SHAPE_TYPE.FLOWCHART_TERMINATOR
            ]:
                other_step_shapes += 1
        elif shape.shape_type == MSO_SHAPE_TYPE.LINE:
            # These are line connectors/arrows (ideal for flowchart connections)
            arrow_connectors += 1

    total_step_shapes = rounded_rectangles + other_step_shapes

    # Evaluate flowchart shape appropriateness
    if rounded_rectangles >= 3 and arrow_connectors >= 2:
        return f"Excellent flowchart shapes: {rounded_rectangles} rounded rectangles and {arrow_connectors} arrow connectors.", 1.0
    elif total_step_shapes >= 3 and arrow_connectors >= 2:
        return f"Good flowchart shapes: {total_step_shapes} step shapes ({rounded_rectangles} rounded) and {arrow_connectors} connectors.", 0.9
    elif total_step_shapes >= 2 and arrow_connectors >= 1:
        return f"Adequate flowchart shapes: {total_step_shapes} step shapes ({rounded_rectangles} rounded) and {arrow_connectors} connectors.", 0.8
    elif total_step_shapes >= 2:
        return f"Found {total_step_shapes} step shapes but only {arrow_connectors} connectors. Missing arrows.", 0.6
    elif arrow_connectors >= 1:
        return f"Found {arrow_connectors} connectors but only {total_step_shapes} step shapes. Need more boxes.", 0.4
    else:
        return f"Insufficient flowchart shapes: {total_step_shapes} step shapes, {arrow_connectors} connectors.", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)

    if len(prs.slides) < 3:
        return "Modified presentation does not have 3 slides.", 0.0

    slide = prs.slides[2]  # Slide 3

    # Check text readability in flowchart shapes
    readable_shapes = 0
    total_text_shapes = 0

    for shape in slide.shapes:
        if shape.is_placeholder:
            continue

        if hasattr(shape, "text") and shape.text and shape.text.strip():
            total_text_shapes += 1

            # Check if text is readable (basic criteria: has text and is not too small)
            try:
                # If we can read the text and it's meaningful, consider it readable
                text = shape.text.strip()
                if len(text) > 2:  # More than just 1-2 characters
                    readable_shapes += 1

                # Additional check for font size if available
                try:
                    for paragraph in shape.text_frame.paragraphs:
                        for run in paragraph.runs:
                            if run.font.size and run.font.size.pt >= 12:
                                # Already counted as readable, but this confirms good size
                                break
                except:
                    pass  # Font size check failed, but text is still readable

            except Exception:
                continue

    if total_text_shapes == 0:
        return "No text shapes found in flowchart.", 0.0

    ratio = readable_shapes / total_text_shapes

    if ratio >= 0.8:
        return f"Flowchart text is clear and readable ({readable_shapes}/{total_text_shapes} shapes).", 1.0
    elif ratio >= 0.5:
        return f"Most flowchart text is readable ({readable_shapes}/{total_text_shapes} shapes).", 0.8
    else:
        return f"Flowchart text clarity needs improvement ({readable_shapes}/{total_text_shapes} shapes).", 0.5
